const Parse = require\('parse/node'\);
Parse.initialize\(process.env.PARSE_APP_ID, process.env.PARSE_JAVASCRIPT_KEY, process.env.PARSE_MASTER_KEY\);
Parse.serverURL = 'http://localhost:1555/parse';
\(async \(\) => {
  const q = new Parse.Query\('Sequence'\);
  q.limit\(3\);
  const seqs = await q.find\({ useMasterKey: true }\);
  for \(const s of seqs\) {
    const emails = s.get\('emails'\) || [];
    console.log\('=== Sequence:', s.get\('nom'\), '==='\);
    if \(emails[0]\) console.log\('email[0] keys:', Object.keys\(emails[0]\)\);
    if \(emails[0]\) console.log\('email[0] sample:', JSON.stringify\(emails[0]\).substring\(0, 500\)\);
  }
}\)\(\).catch\(console.error\);
